        t.addLesson(new Lesson("1. What does \u201cpercent\u201d mean?", "<p>The word <strong>percent</strong> literally means <em>\u201cper hundred\u201d</em> (<em>cent</em> = 100, like 100 cents in a dollar). So 40% just means <strong>40 out of every 100</strong>.</p>" + Doc.analogy("Imagine every quantity cut into 100 equal slices, like a giant pizza with 100 slices. 25% is 25 slices, 50% is half the pizza, 100% is the whole pizza.") + "<h4>Three ways to write the same thing</h4>" + Doc.formula("40% &nbsp;=&nbsp; 40/100 &nbsp;=&nbsp; 0.40") + "<p>To turn a percent into a decimal, divide by 100 (slide the dot two places left). To turn a decimal into a percent, multiply by 100 (slide the dot two places right).</p><h4>Friendly fractions worth memorising</h4><table><tr><th>Fraction</th><th>Percent</th></tr><tr><td>1/2</td><td>50%</td></tr><tr><td>1/4</td><td>25%</td></tr><tr><td>1/5</td><td>20%</td></tr><tr><td>1/8</td><td>12.5%</td></tr><tr><td>1/3</td><td>33\u2153%</td></tr><tr><td>1/10</td><td>10%</td></tr></table>" + Doc.tip("Knowing these by heart turns slow questions into instant ones. Seeing \u201c25% of something\u201d? Just take a quarter of it.") + Doc.recap("Percent = out of 100. Any percent is also a fraction (over 100) and a decimal."), 1, "percent-meaning", STRAT_MEANING));
