        t.addLesson(new Lesson("4. Successive (back-to-back) changes", "<p>What if something changes twice \u2014 say a price goes up 25% and then drops 20%? You <strong>cannot</strong> just add and subtract the percents, because the second change acts on a <em>new</em> amount.</p>" + Doc.warn("+25% then \u221220% is <strong>not</strong> +5%. The second percent is taken from a bigger number, so the pieces don't cancel the way they look.") + "<h4>The reliable multiplier method</h4>" + Doc.steps("Turn each change into a multiplier (+25% \u2192 1.25, \u221220% \u2192 0.80).", "Multiply them together: 1.25 \u00d7 0.80 = 1.00.", "A multiplier of 1.00 means <strong>no net change</strong> (0%).") + Doc.example("Start with 100", "Up 25%: 100 \u2192 125. Down 20% of 125 = 25 off \u2192 100. Back to where we started \u2014 net change is <strong>0%</strong>, exactly as the multipliers predicted.") + "<h4>The quick formula</h4>" + Doc.formula("net% = a + b + (a \u00d7 b) \u00f7 100") + "<p>For +20% then +20%: 20 + 20 + (400\u00f7100) = 44% (not 40%).</p>" + Doc.tip("The multiplier method never lets you down and works for any number of changes \u2014 just keep multiplying.") + Doc.recap("For successive changes, multiply the multipliers. Adding percents is a trap."), 4, "percent-successive", STRAT_SUCCESSIVE));
